import { WorkflowRuntime } from 'mastra/workflows';

const monitorTokens = (workflow: WorkflowRuntime) => {
  const stepTokens: Record<string, { input: number; output: number }> = {};

  workflow.on('step:executing', ({ nodeId, input }) => {
    stepTokens[nodeId] = { input: estimateTokens(input), output: 0 };
  });

  workflow.on('step:completed', ({ nodeId, output }) => {
    stepTokens[nodeId].output = estimateTokens(output);
    const total = stepTokens[nodeId].input + stepTokens[nodeId].output;
    if (total > 2000) {
      console.warn(`⚠️ High token step: ${nodeId} (${total} tokens)`);
    }
  });

  return stepTokens;
};

function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4); // Rough GPT token estimation
}

import { AgentRuntime } from 'mastra/agents';

const toolCostMonitor = (agent: AgentRuntime) => {
  agent.toolManager.intercept('call', (toolCall) => {
    const response = toolCall.execute();
    const tokenCost = estimateTokens(JSON.stringify(response));

    if (tokenCost > 1000) {
      console.error(`🚨 Expensive tool: ${toolCall.name} (${tokenCost} tokens)`);
      console.log('Response keys:', Object.keys(response));
    }

    return response;
  });
};

import { KnowledgeBase } from 'mastra/knowledge';

const monitorMemory = (kb: KnowledgeBase) => {
  kb.on('retrieval', (query, memories) => {
    const totalTokens = memories.reduce((sum, mem) => 
      sum + estimateTokens(mem.content), 0
    );

    if (totalTokens > 3000) {
      console.warn(`💾 Memory bloat: ${memories.length} items (${totalTokens} tokens)`);
    }

    // Check for staleness
    const stale = memories.filter(mem => 
      Date.now() - new Date(mem.timestamp).getTime() > 7 * 24 * 60 * 60 * 1000
    );
    if (stale.length > 0) {
      console.warn(`🕰️ Stale memories: ${stale.length}/${memories.length}`);
    }
  });
};

