import { WorkflowRuntime } from 'mastra/workflows';

const tokenOptimizer = (workflow: WorkflowRuntime) => {
  workflow.on('step:completed', ({ output }) => {
    // Extract only the core response, strip metadata
    const optimized = extractCoreContent(output);
    const originalSize = estimateTokens(JSON.stringify(output));
    const optimizedSize = estimateTokens(optimized);

    console.log(`📉 Optimized: ${originalSize} → ${optimizedSize} tokens (${Math.round((1 - optimizedSize/originalSize)*100)}% savings)`);

    return optimized;
  });
};

function extractCoreContent(output: any): string {
  if (typeof output === 'string') return output.slice(0, 4000);
  if (output.content) return output.content;
  if (output.response) return output.response;
  if (output.text) return output.text;
  return JSON.stringify(output).slice(0, 4000);
}

import { AgentRuntime } from 'mastra/agents';

const normalizeToolResponses = (agent: AgentRuntime) => {
  const originalCall = agent.toolManager.call.bind(agent.toolManager);

  agent.toolManager.call = async (toolName: string, params: any) => {
    const result = await originalCall(toolName, params);

    const normalized = {
      success: true,
      data: result.data || result,
      // Strip verbose fields
      ...('metadata' in result ? {} : { metadata: result.metadata })
    };

    return normalized;
  };
};

import { KnowledgeBase } from 'mastra/knowledge';

const smartPruner = (kb: KnowledgeBase) => {
  const originalRetrieve = kb.retrieve.bind(kb);

  kb.retrieve = async (query: string, limit = 5) => {
    let memories = await originalRetrieve(query, limit * 3);

    // Prune by recency (last 7 days)
    memories = memories.filter(mem => 
      Date.now() - new Date(mem.timestamp).getTime() < 7 * 24 * 60 * 60 * 1000
    );

    // Rank by semantic similarity
    memories.sort((a, b) => semanticScore(query, b.content) - semanticScore(query, a.content));

    return memories.slice(0, limit);
  };
};

